import json
import logging
from google.cloud import storage, firestore, pubsub_v1
from google.cloud.exceptions import NotFound

def process_file_from_gcs(event, context):
    """Triggered by a change to a Cloud Storage bucket.
    Args:
        event (dict): Event payload.
        context (google.cloud.functions.Context): Metadata for the event.
    """
    
    # Initialize clients
    storage_client = storage.Client()
    firestore_client = firestore.Client()
    pubsub_client = pubsub_v1.PublisherClient()
    
    # Get bucket and file information from the event
    bucket_name = event['bucket']
    file_name = event['name']
    
    # Get the bucket and file
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    # Read file content
    file_content = blob.download_as_text()
    
    # Process the file (example: parse JSON)
    try:
        data = json.loads(file_content)
    except json.JSONDecodeError:
        logging.error(f"Failed to parse JSON from {file_name}")
        return
    
    # Write to Firestore
    try:
        db = firestore_client.collection('processed_files').document(file_name)
        db.set(data)
        logging.info(f"Successfully wrote to Firestore: {file_name}")
    except Exception as e:
        logging.error(f"Failed to write to Firestore: {e}")
        return
    
    # Publish to Pub/Sub
    try:
        topic_path = pubsub_client.topic_path('your-project-id', 'your-topic-name')
        message = json.dumps({
            'file_name': file_name,
            'bucket': bucket_name,
            'processed_data': data
        }).encode('utf-8')
        
        publish_future = pubsub_client.publish(topic_path, message)
        publish_future.result()
        logging.info(f"Successfully published to Pub/Sub: {file_name}")
    except Exception as e:
        logging.error(f"Failed to publish to Pub/Sub: {e}")
        return
    
    logging.info(f"Successfully processed file: {file_name}")